final class PromoManager {
    static let shared = PromoManager()
    private init() {}

    struct Promo {
        let code: String
        let discount: Int
    }

    private(set) var appliedPromos: [Promo] = []

    func handleUniversalLink(url: URL) -> Bool {
        guard url.scheme?.lowercased() == "https",
              url.host?.lowercased() == "myapp.com",
              url.path == "/promo" else {
            return false
        }

        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let code = components.queryItems?.first(where: { $0.name == "code" })?.value,
              let discountString = components.queryItems?.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString) else {
